import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const ROOT = path.resolve(__dirname, '..');

// Load the mapping generated by upload-to-cloudinary.mjs
const mappingPath = path.join(ROOT, 'scripts', 'cloudinary-mapping.json');

if (!fs.existsSync(mappingPath)) {
    console.error('❌ cloudinary-mapping.json not found!');
    console.error('   Run "node scripts/upload-to-cloudinary.mjs" first to upload images.');
    process.exit(1);
}

const mapping = JSON.parse(fs.readFileSync(mappingPath, 'utf-8'));
console.log(`📄 Loaded ${Object.keys(mapping).length} image mappings from cloudinary-mapping.json\n`);

// Files that contain image path references
const DATA_FILES = [
    'src/app/templates/avenix/data.js',
    'src/app/templates/blissly/data.js',
    'src/app/templates/flara/data.js',
    'src/app/templates/flavornest/data.js',
    'src/app/templates/aurora/data.js',
    'src/app/templates/aurora/page.js',
    'src/app/templates/frostify/data.js',
];

let totalReplacements = 0;

for (const relFile of DATA_FILES) {
    const filePath = path.join(ROOT, relFile);

    if (!fs.existsSync(filePath)) {
        console.log(`⚠️  Skipped (not found): ${relFile}`);
        continue;
    }

    let content = fs.readFileSync(filePath, 'utf-8');
    let fileReplacements = 0;

    for (const [localPath, cloudinaryUrl] of Object.entries(mapping)) {
        // Escape special regex characters in the local path
        const escaped = localPath.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        // Match the path in both double and single quotes
        const regexDouble = new RegExp(`"${escaped}"`, 'g');
        const regexSingle = new RegExp(`'${escaped}'`, 'g');

        const matchesDouble = content.match(regexDouble);
        const matchesSingle = content.match(regexSingle);

        if (matchesDouble) {
            content = content.replace(regexDouble, `"${cloudinaryUrl}"`);
            fileReplacements += matchesDouble.length;
        }
        if (matchesSingle) {
            content = content.replace(regexSingle, `'${cloudinaryUrl}'`);
            fileReplacements += matchesSingle.length;
        }
    }

    if (fileReplacements > 0) {
        fs.writeFileSync(filePath, content);
        console.log(`✅ ${relFile} — ${fileReplacements} path(s) replaced`);
        totalReplacements += fileReplacements;
    } else {
        console.log(`⏭️  ${relFile} — no changes needed`);
    }
}

console.log(`\n${'─'.repeat(60)}`);
console.log(`✨ Sync complete! ${totalReplacements} total replacements across ${DATA_FILES.length} files.`);
console.log(`\n   Your template images now load from Cloudinary! 🎉`);
console.log(`   Run "npm run dev" to verify everything looks good.`);
